using System.ComponentModel;
using System.Net;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = "gpt-4o-mini-2024-07-18";

// --- Build the chat client through MEAI ---
IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Define tools ---
var tools = new List<AITool>
{
    AIFunctionFactory.Create(ResearchTools.WebSearch),
    AIFunctionFactory.Create(ResearchTools.SaveNote),
    AIFunctionFactory.Create(ResearchTools.GetNotes),
};

// --- Create the agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. When given a topic:
        1. Use the WebSearch tool multiple times with different queries to gather information.
        2. Use the SaveNote tool to record key findings as you go.
        3. Use GetNotes to review what you have collected.
        4. Once you have enough information, write a well-structured summary
           with an introduction, key findings, and conclusion.
        Be thorough but concise. Cite your sources where possible.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools: tools);

// --- Get the topic from the user ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

// --- Run the agent ---
var session = await agent.CreateSessionAsync();
var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
    },
};

var response = await agent.RunAsync($"Research the following topic and provide a summary: {topic}", session, runOptions);

Console.WriteLine("═══════════════════════════════════════════");
Console.WriteLine("  RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════════");
Console.WriteLine(response.Text);
Console.WriteLine("═══════════════════════════════════════════");

if (response.Usage is { } usage)
{
    Console.WriteLine($"\nTokens — input: {usage.InputTokenCount}, output: {usage.OutputTokenCount}, total: {usage.TotalTokenCount}");
}

// --- Tool implementations ---
static class ResearchTools
{
    private static readonly List<string> s_notes = [];
