+// --- Tool implementations ---
+static class ResearchTools
+{
+    private static readonly List<string> s_notes = [];
+    private static readonly HttpClient s_httpClient = new()
+    {
+        DefaultRequestHeaders =
+        {
+            { "User-Agent", "ResearchAgent/1.0" },
+        },
+    };
+
+    [Description("Search the web for information on a query. Returns relevant search result snippets.")]
+    public static async Task<string> WebSearch(
+        [Description("The search query to look up")] string query)
+    {
+        try
+        {
+            // Use DuckDuckGo's HTML search (no API key required)
+            var encoded = WebUtility.UrlEncode(query);
+            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
+            var html = await s_httpClient.GetStringAsync(url);
+
+            var snippets = ExtractSnippets(html);
+            if (snippets.Count == 0)
+            {
+                return $"No results found for: {query}";
+            }
+
+            return $"Search results for '{query}':\n" +
+                   string.Join("\n\n", snippets.Select((s, i) => $"[{i + 1}] {s}"));
+        }
+        catch (Exception ex)
+        {
+            return $"Search failed for '{query}': {ex.Message}";
+        }
+    }
+
+    [Description("Save a research note for later reference.")]
+    public static string SaveNote(
+        [Description("The note content to save")] string note)
+    {
+        s_notes.Add(note);
+        return $"Note #{s_notes.Count} saved.";
+    }
+
+    [Description("Retrieve all saved research notes.")]
+    public static string GetNotes()
+    {
+        if (s_notes.Count == 0)
+        {
+            return "No notes saved yet.";
+        }
+
+        return "Saved notes:\n" +
+               string.Join("\n", s_notes.Select((n, i) => $"[{i + 1}] {n}"));
+    }
+
+    private static List<string> ExtractSnippets(string html)
+    {
+        var snippets = new List<string>();
+        const int maxSnippets = 5;
+
+        // Extract text from DuckDuckGo result snippets (class="result__snippet")
+        var searchTag = "class=\"result__snippet\"";
+        var idx = 0;
+        while (snippets.Count < maxSnippets)
+        {
+            idx = html.IndexOf(searchTag, idx, StringComparison.Ordinal);
+            if (idx < 0) break;
+
+            var start = html.IndexOf('>', idx) + 1;
+            var end = html.IndexOf("</", start, StringComparison.Ordinal);
+            if (start <= 0 || end < 0) break;
+
+            var text = WebUtility.HtmlDecode(
+                System.Text.RegularExpressions.Regex.Replace(
+                    html[start..end], "<[^>]+>", " "))
+                .Trim();
+
+            if (text.Length > 20)
+            {
+                snippets.Add(text);
+            }
+
+            idx = end;
+        }
+
+        return snippets;
+    }
+}
